// AddLandowner for LTA Step 1
// PARAMS - formID, roles, businessID
const websvcName = "LibCreateContactInformationRelation";

// Get the Relation Type
const relationType = VV.Form.GetFieldValue("Landowner Business Or Individual");

// Determine the label based on the Relation Type
let label;
if (relationType === "Business") {
  label = "Business Signer";
} else {
  label = "Landowner";
}

let CallServerSide = function () {
  VV.Form.ShowLoadingPanel();

  // Create the form data to send to the microservice
  const formData = [
    {
      name: "Relation Type",
      value: relationType,
    },
    {
      name: "Related Record ID",
      value: VV.Form.DhDocID,
    },
    {
      name: "Contact Information ID",
      value: formID,
    },
    {
      name: "Business ID",
      value: businessID,
    },
  ];

  // Ensure 'roles' is an array before iterating
  if (Array.isArray(roles)) {
    // Iterate through the roles array and add them to the form data
    roles.forEach(function (roleName) {
      formData.push({
        name: roleName,
        value: "True",
      });
    });
  }

  // Convert form data to JSON and prepare the server-side call
  let data = JSON.stringify(formData);
  let requestObject = $.ajax({
    type: "POST",
    url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${websvcName}`,
    contentType: `application/json; charset=utf-8`,
    data: data,
  });

  return requestObject;
};

$.when(CallServerSide()).always(function (resp) {
  VV.Form.HideLoadingPanel();
  let messageData = "";

  if (typeof resp.status != "undefined") {
    messageData = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;
    displayErrorModal(messageData);
  } else if (typeof resp.statusCode != "undefined") {
    messageData = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server. This may mean that the servers to run the business logic are not available.`;
    displayErrorModal(messageData);
  } else if (resp.meta.status == "200") {
    if (resp.data[0] !== "undefined") {
      if (resp.data[0] === "Success") {
        // Check if the record was updated
        const recordUpdated = !!resp.data?.[2]?.recordUpdated;
        if (recordUpdated) {
          // Extract updated fields from the response
          const updatedFields = resp.data?.[2]?.updatedFields || {};
          const updatedFieldsList = Object.entries(updatedFields)
            .filter(([field, value]) => value === "True" || value === "False")
            .map(([field]) => field); // Get field names only

          // Generate a user-friendly message listing updated fields
          const updatedFieldsMessage =
            updatedFieldsList.length > 0
              ? `The following roles were updated: ${updatedFieldsList.join(
                  ", "
                )}.`
              : "No specific roles were updated.";

          // Construct success message
          let successMessage = `We've updated the existing ${label} record associated with this application. ${updatedFieldsMessage}`;

          // Display success modal
          VV.Form.Global.DisplayModal({
            Title: `${label} Updated`,
            Icon: "success",
            HtmlContent: `<p style="text-align: center; font-size: 1.1em;">${successMessage}</p>`,
            showCancelButton: false,
            allowOutsideClick: false,
            okFunction: function () {
              VV.Form.RefreshDataGridControl("DG Landowners");
              VV.Form.RefreshDataGridControl("DG Timber Owners");
              VV.Form.RefreshDataGridControl("DG Operators");
              clearFields();
            },
          });
        } else {
          // If the record was not updated, this indicates a new record was created
          let successMessage = `You've successfully associated the ${label} with this application.`;

          // Display success modal
          VV.Form.Global.DisplayModal({
            Title: `${label} Associated`,
            Icon: "success",
            HtmlContent: `<p style="text-align: center; font-size: 1.1em;">${successMessage}</p>`,
            showCancelButton: false,
            allowOutsideClick: false,
            okFunction: function () {
              VV.Form.RefreshDataGridControl("DG Landowners");
              VV.Form.RefreshDataGridControl("DG Timber Owners");
              VV.Form.RefreshDataGridControl("DG Operators");
              clearFields();
            },
          });
        }
      } else if (resp.data[0] === "Error") {
        messageData = `An error was encountered. ${resp.data[1]}`;
        displayErrorModal(messageData);
      } else {
        messageData = `An unhandled response occurred when calling ${websvcName}. The form will not save at this time. Please try again or communicate this issue to support.`;
        displayErrorModal(messageData);
      }
    } else {
      messageData = "The status of the response returned as undefined.";
      displayErrorModal(messageData);
    }
  } else {
    messageData = `The following unhandled response occurred while attempting to retrieve data from ${websvcName}: ${resp?.data?.error}`;
    displayErrorModal(messageData);
  }
});

// Clear field values
function clearFields() {
  VV.Form.SetFieldValue("Landowner Search First Name", "");
  VV.Form.SetFieldValue("Landowner Search Last Name", "");
  VV.Form.SetFieldValue("Landowner Search Country", "Select Item");
  VV.Form.SetFieldValue("Landowner Search Postal Zip Code", "");
  VV.Form.SetFieldValue("Landowner Search Address Line 1", "");
  VV.Form.SetFieldValue("Landowner Search Address Line 2", "");
  VV.Form.SetFieldValue("Landowner Search Address Line 3", "");
  VV.Form.SetFieldValue("Landowner Search City", "");
  VV.Form.SetFieldValue("Landowner Search Province State", "Select Item");
  VV.Form.SetFieldValue("Landowner Search County", "Select Item");
  VV.Form.SetFieldValue("Landowner Search Phone", "");
  VV.Form.SetFieldValue("Landowner Search Email", "");
}

// Display error modal
function displayErrorModal(messageData) {
  const unableText = `Unable to add ${label}`;
  let icon = "error";
  if (messageData.includes("Duplicate")) {
    icon = "warning";
    messageData = `Duplicate Found: The selected ${label} is already associated with this application.`;
  }
  VV.Form.Global.DisplayModal({
    Title: unableText,
    Icon: icon,
    HtmlContent: messageData,
  });
}

// AddNewContact for LTA Step 1
// Param - contactData

// Template GUID goes here
const templateId = "8a436bcc-c1a6-ef11-aa66-efba905911ab"; // Contact Information

let {
  contactFirstName,
  contactLastName,
  contactPhone,
  contactEmail,
  contactCountry,
  contactZipCode,
  contactAddressLine1,
  contactAddressLine2,
  contactAddressLine3,
  contactCity,
  contactProvinceState,
  contactCounty,
  role,
  relationType
} = contactData;

// Check and process the first name
if (!VV.Form.Global.isNullEmptyUndefined(contactFirstName)) {
  contactFirstName = VV.Form.Global.ToProperCase(contactFirstName);
}

// Check and process the last name
if (!VV.Form.Global.isNullEmptyUndefined(contactLastName)) {
  contactLastName = VV.Form.Global.ToProperCase(contactLastName);
}

if (!VV.Form.Global.isNullEmptyUndefined(contactAddressLine1)) {
  contactAddressLine1 = VV.Form.Global.ToProperCase(contactAddressLine1);
}
if (!VV.Form.Global.isNullEmptyUndefined(contactAddressLine2)) {
  contactAddressLine2 = VV.Form.Global.ToProperCase(contactAddressLine2);
}
if (!VV.Form.Global.isNullEmptyUndefined(contactAddressLine3)) {
  contactAddressLine3 = VV.Form.Global.ToProperCase(contactAddressLine3);
}

if (!VV.Form.Global.isNullEmptyUndefined(contactCity)) {
  contactCity = VV.Form.Global.ToProperCase(contactCity);
}

// Create the landowner data object
const contactObj = {
  "Related Record ID": VV.Form.DhDocID,
  "Relation Type": relationType,
  "Role": role,
};

const label = role + " Search";

// Field mappings
const fieldMappings = [
  { sourceFieldName: `Form ID`, sourceFieldValue: VV.Form.DhDocID, targetFieldName: "Related Record ID", },
  { sourceFieldName: `${label} First Name`, sourceFieldValue: contactFirstName, targetFieldName: "First Name" },
  { sourceFieldName: `${label} Last Name`, sourceFieldValue: contactLastName, targetFieldName: "Last Name" },
  { sourceFieldName: `${label} Phone`, sourceFieldValue: contactPhone, targetFieldName: "Phone" },
  { sourceFieldName: `${label} Email`, sourceFieldValue: contactEmail, targetFieldName: "Email" },
  { sourceFieldName: `${label} Country`, sourceFieldValue: contactCountry, targetFieldName: "Country" },
  { sourceFieldName: `${label} Postal Zip Code`, sourceFieldValue: contactZipCode, targetFieldName: "Zip Code" },
  { sourceFieldName: `${label} Address Line 1`, sourceFieldValue: contactAddressLine1, targetFieldName: "Address Line 1" },
  { sourceFieldName: `${label} Address Line 2`, sourceFieldValue: contactAddressLine2, targetFieldName: "Address Line 2" },
  { sourceFieldName: `${label} Address Line 3`, sourceFieldValue: contactAddressLine3, targetFieldName: "Address Line 3" },
  { sourceFieldName: `${label} City`, sourceFieldValue: contactCity, targetFieldName: "City" },
  { sourceFieldName: `${label} Province State`, sourceFieldValue: contactProvinceState, targetFieldName: "State" },
  { sourceFieldName: `${label} County`, sourceFieldValue: contactCounty, targetFieldName: "County" },
  // JSON Object holding information for contact creation process.
  { sourceFieldName: "contactObj", sourceFieldValue: JSON.stringify(contactObj), targetFieldName: "JSON Add Contact" },
];

// Save the form and relate it using field mappings
VV.Form.DoAjaxFormSave().then(() => {
  VV.Form.Global.FillinAndRelateForm(templateId, fieldMappings);
});

