function generateFeeAndShowSendForSignature() {
  return VV.Form.Template.CallLibLTAStep1GenerateFeeSummary()
    .then((feeAmount) => {
      //VV.Form.SetFieldValue("No Fees Required", feeAmount === 0 ? "True" : "False");
      VV.Form.SetFieldValue('Fees Assesed', 'True');

      //Check again all fees, in case the user is Re-Validating and a higher fee was already associated
      return VV.Form.Global.GetPendingRelatedFees();
    })
    .then((result) => {
      VV.Form.SetFieldValue('No Fees Required', result.length > 0 ? 'False' : 'True');
      let message = `$0.00 in the total fees assessed.`;
      let flagUpdates = [];

      if (result.length > 0) {
        const signaturesCompleted = VV.Form.GetFieldValue('Signatures Completed') === 'True';
        message = `Payment of $${result[0]['total Amount Due']} can be made in the Shopping Cart${!signaturesCompleted ? ' once all required signatures have been obtained' : ''}.`;

        const dateOfReceipt = VV.Form.GetFieldValue('Date of Receipt');

        if (dateOfReceipt === '' || dateOfReceipt === null || dateOfReceipt === 'Invalid Date') {
          flagUpdates = [
            VV.Form.SetFieldValue("AutoSubmissionNeeded", "True"),
            VV.Form.SetFieldValue("AutoResubmitNeeded", "False"),
          ];
        } else {
          flagUpdates = [
            VV.Form.SetFieldValue("AutoSubmissionNeeded", "False"),
            VV.Form.SetFieldValue("AutoResubmitNeeded", "True"),
          ];
        }
      } else {
          flagUpdates = [
            VV.Form.SetFieldValue("AutoSubmissionNeeded", "False"),
            VV.Form.SetFieldValue("AutoResubmitNeeded", "False"),
          ];
      }

      return Promise.all(flagUpdates).then(function () {
        return VV.Form.Global.DisplayModal({
          Icon: "success",
          Title: "Success",
          HtmlContent: message,
        });
      });
    })
    .catch((error) => {
      VV.Form.Global.DisplayModal({
        Title: 'Error',
        Icon: 'error',
        HtmlContent: error,
      });
    });
}

