// Function to display the "Add Contact" modal
function showAddContactModal(selectedBusinessId, selectedBusinessName) {
  let addContactHtml;

  if(!isBusinessSigner){
    addContactHtml = `
    <div style="text-align: left; line-height: 1.6;">
      <p>Are you sure you want to associate the selected contact as a ${mainRole}?</p>
      <p><strong>Name:</strong> ${selectedContactFirstName} ${selectedContactLastName}</p>
    </div>
  `;
  }else{    
    addContactHtml = `
    <div style="text-align: left; line-height: 1.6;">
      <p>Are you sure you want to associate the selected contact as a Business Signer?</p>
      <p><strong>Business Signer:</strong> ${selectedContactFirstName} ${selectedContactLastName}</p>
      <p><strong>${mainRole}:</strong> ${selectedBusinessName}</p>
    </div>
  `;
  }

  Swal.fire({
    icon: 'question',
    title: `Add ${isBusinessSigner ? 'Business Signer' : mainRole}`,
    html: addContactHtml,
    showCancelButton: true,
    showConfirmButton: true,
    showDenyButton: true,
    allowOutsideClick: false,
    confirmButtonText: 'Back',
    denyButtonText: `Add ${isBusinessSigner ? 'Business Signer' : mainRole}`,
    cancelButtonText: 'Cancel',
    width: '40rem', // Modal width for Add Contact
    didRender: () => {
      // Rearrange buttons
      const actions = Swal.getActions(); // Get the actions container
      const confirmButton = Swal.getConfirmButton(); // Back button
      const denyButton = Swal.getDenyButton(); // Add Contact button
      const cancelButton = Swal.getCancelButton(); // Cancel button

      // Set custom order using flexbox order property
      confirmButton.style.order = 1; // Back button
      denyButton.style.order = 2; // Add Contact button
      cancelButton.style.order = 3; // Cancel button

      // Directly modify the deny button style after rendering
      $('.swal2-deny').css({
        'background-color': $('.swal2-confirm').css('background-color'),
        color: $('.swal2-confirm').css('color'),
      });

      // Ensure the actions container uses flexbox
      actions.style.display = 'flex';
    },
  }).then((result) => {
    if (result.isConfirmed) {
      if(isBusinessSigner) {
        showAssociateBusinessModal(); // Go to "Associate Business" modal
      } else {
        showSearchResultsModal(); // Go back to the "Select Contact" modal
      }
    } else if (result.isDenied) {
      VV.Form.DoAjaxFormSave().then(() => {
        addSelectedContact(
          selectedContactId,
          selectedBusinessId
        );
      });
    } else if (result.isDismissed) {
      // Call clearFieldsCallback when modal is closed or canceled
      clearFieldsCallback();
    }
  });
}

// Callback function to add the selected contact record and other params
