// AddressFieldNamesMap for Forest Practices Application/Notification

/*
  This function returns an address object with field names mapped to the appropriate field names for the form.

  Function name: AddressFieldNamesMap

  Parameter:
  - addressType: a string specifying the address set to map field names for (e.g. "mailingAddress", "physicalAddress").
  - hasCountry: a boolean specifying whether the address has a country field or not.
*/

const landOwnerInformationMailingAddressMap = new Map([
    ['street1', 'Address Line 1'],
    ['city', 'City'],
    ['state', 'State'],
    ['zipCode', 'Zip Code'],
    ['country', 'Country'],
]);


let addressFieldNamesMap;
switch (addressType) {
    case 'landOwnerInformationAddress':
        addressFieldNamesMap = landOwnerInformationMailingAddressMap;
        break;
    default:
        throw new Error('Invalid address type specified.');
}

const address = {};
for (const [key, value] of addressFieldNamesMap) {
    address[key] = value;
}

if (hasCountry) {
    address.hasCountry = true;
} else {
    address.hasCountry = false;
}

return address;

//BusinessSearch for LTA Step 1
//Params - role
const websvcName = 'LibBusinessSearch';
let modalContent;

// Define the maximum number of results allowed before prompting the user to refine their search
const recordThreshold = 50;

//Define the maximum number of results allowed to include the "Add Business" button
const addBusinessThreshold = 25;

// Determine the correct prefix based on the role
let prefix;

switch (role) {
  case 'Landowner':
    prefix = 'Landowner Business';
    break;
  case 'Timber Owner':
    prefix = 'Timber Owner Business';
    break;
  case 'Operator':
    prefix = 'Operator Business';
    break;
  default:
    throw new Error(`Invalid role: ${role}`);
}

let CallServerSide = function () {
  VV.Form.ShowLoadingPanel();
  // Use the determined prefix to build formData
  const formData = [
    {
      name: 'Business ID Number',
      value: VV.Form.GetFieldValue(`${prefix} Search Business ID Number`),
    },
    {
      name: 'Business Name',
      value: VV.Form.GetFieldValue(`${prefix} Search Business Name`),
    },
    {
      name: 'Business Country',
      value: VV.Form.GetFieldValue(`${prefix} Search Country`),
    },
    {
      name: 'Business Zip Code',
      value: VV.Form.GetFieldValue(`${prefix} Search Postal Zip Code`),
    },
    {
      name: 'Business Address Line 1',
      value: VV.Form.GetFieldValue(`${prefix} Search Address Line 1`),
    },
    {
      name: 'Business Address Line 2',
      value: VV.Form.GetFieldValue(`${prefix} Search Address Line 2`),
    },
    {
      name: 'Business Address Line 3',
      value: VV.Form.GetFieldValue(`${prefix} Search Address Line 3`),
    },
    {
      name: 'Business City',
      value: VV.Form.GetFieldValue(`${prefix} Search City`),
    },
    {
      name: 'Business Province State',
      value: VV.Form.getDropDownListText(`${prefix} Search Province State`),
    },
    {
      name: 'Business County',
      value: VV.Form.GetFieldValue(`${prefix} Search County`),
    },
    {
      name: 'Business Phone',
      value: VV.Form.GetFieldValue(`${prefix} Search Phone`),
    },
    {
      name: 'Business Email',
      value: VV.Form.GetFieldValue(`${prefix} Search Email`),
    },
  ];

  // Convert form data to JSON and prepare the server-side call
  let data = JSON.stringify(formData);
  let requestObject = $.ajax({
    type: 'POST',
    url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${websvcName}`,
    contentType: `application/json; charset=utf-8`,
    data: data,
  });

  return requestObject;
};

$.when(CallServerSide()).always(function (resp) {
  VV.Form.HideLoadingPanel();
  let messageData = '';

  if (typeof resp.status != 'undefined') {
    messageData = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;
    displayErrorModal(messageData);
  } else if (typeof resp.statusCode != 'undefined') {
    messageData = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server. This may mean that the servers to run the business logic are not available.`;
    displayErrorModal(messageData);
  } else if (resp.meta.status == '200') {
    if (resp.data[0] !== 'undefined') {
      if (resp.data[0] === 'Success') {
        const searchResults = resp.data[2].results;

        // Check if the number of records exceeds the threshold
        if (searchResults.length >= recordThreshold) {
          modalContent = `Too many results were returned. Please refine your search criteria to narrow down the results.`;
          VV.Form.Global.DisplayModal({
            Icon: 'warning',
            Title: 'Refine Search',
            HtmlContent: modalContent,
            showCancelButton: false,
            ConfirmText: 'OK',
          });
        } else if (searchResults.length > 0) {
          // Format the search results to be displayed in rows, including Business ID
          const recordsArray = searchResults.map((record) => ({
            'business Name': record['business Name'] || 'N/A',
            'business ID Number': record['business ID Number'] || 'N/A',
            'business ID': record['business ID'] || 'N/A', // Add Business ID here
            'business Country': record['business Country'] || 'N/A',
            'business Zip Code': record['business Zip Code'] || 'N/A',
            'business Address Line 1': record['business Address Line 1'] || 'N/A',
            'business City': record['business City'] || 'N/A',
            'business Province State': record['business Province State'] || 'N/A',
          }));

          // Display the modal with results, passing callback functions
          VV.Form.Template.AddBusinessRecordModal(
            recordsArray,
            clearFieldsCallback,
            role,
            prefix,
            searchResults.length < addBusinessThreshold
          );
        } else {
          VV.Form.Global.DisplayModal({
            Icon: 'warning',
            Title: 'Business Search',
            HtmlContent: `No business records were found with the search criteria provided. Please refine your search criteria and try again or click 'Add New Business' to create a new business record.`,
            ConfirmText: 'Add New Business',
            dismissFunction: clearFieldsCallback,
            showCancelButton: true,
            okFunction: function () {
              const business = {
                businessName: VV.Form.GetFieldValue(`${prefix} Search Business Name`),
                businessCountry: VV.Form.GetFieldValue(`${prefix} Search Country`),
                businessZipCode: VV.Form.GetFieldValue(`${prefix} Search Postal Zip Code`),
                businessAddressLine1: VV.Form.GetFieldValue(`${prefix} Search Address Line 1`),
                businessAddressLine2: VV.Form.GetFieldValue(`${prefix} Search Address Line 2`),
                businessAddressLine3: VV.Form.GetFieldValue(`${prefix} Search Address Line 3`),
                businessCity: VV.Form.GetFieldValue(`${prefix} Search City`),
                businessProvinceState: VV.Form.GetFieldValue(`${prefix} Search Province State`),
                businessCounty: VV.Form.GetFieldValue(`${prefix} Search County`),
                businessPhone: VV.Form.GetFieldValue(`${prefix} Search Phone`),
                businessEmail: VV.Form.GetFieldValue(`${prefix} Search Email`),
                role: role
              };
              VV.Form.Template.AddNewBusiness(business);
            },
          });
        }
      } else if (resp.data[0] === 'Error') {
        messageData = `An error was encountered. ${resp.data[1]}`;
        displayErrorModal(messageData);
      } else {
        messageData = `An unhandled response occurred when calling ${websvcName}. The form will not save at this time. Please try again or communicate this issue to support.`;
        displayErrorModal(messageData);
      }
    } else {
      messageData = 'The status of the response returned as undefined.';
      displayErrorModal(messageData);
    }
  } else {
    messageData = `The following unhandled response occurred while attempting to retrieve data from ${websvcName}: ${resp?.data?.error}`;
    displayErrorModal(messageData);
  }
});

// Callback function to clear the field values
function clearFieldsCallback() {
  // Clear the fields dynamically based on the prefix
  VV.Form.SetFieldValue(`${prefix} Search Business ID Number`, '');
