// Resubmit for Step 1 LTA
const isProponent = VV.Form.GetFieldValue('isProponent') === 'True';

if (!isProponent) return doResubmit();

VV.Form.Template.FormValidation().then((isValid) =>
  isValid ? doResubmit() : VV.Form.Global.ValidationModal()
);

function doResubmit() {
  const oldStatus = VV.Form.GetFieldValue('Status');
  VV.Form.Global.DisplayModal({
    Title: 'Confirm',
    Icon: 'question',
    HtmlContent: 'Do you want to move forward with the process?',
    okFunction: () => {
      Promise.all([
        VV.Form.SetFieldValue('Status', 'Revision Received'),
        VV.Form.SetFieldValue('UpdateSubformsToSubmitted', 'True'),
      ])
        .then(() => VV.Form.Template.SetButtonVisibility())
        .then(() => VV.Form.DoAjaxFormSave())
        .then(() => VV.Form.Template.CallLibUpdateApplicationReviewPage())
        .then(() => VV.Form.Template.CreateStatusHistory('Revision Received', oldStatus))
        .then(() => {
          VV.Form.Global.DisplayModal({
            Title: 'Form Saved',
            Icon: 'success',
            HtmlContent: 'Form has been resubmitted successfully.',
          });
        })
        .catch(error => {
          console.error('Error detected:', error);
          VV.Form.Global.DisplayModal({
            Title: 'Error',
            Icon: 'error',
            HtmlContent: 'An error occurred while resubmitting the form. Please try again or contact support.',
          });
        });
    },
  });
}

//SetButtonVisibility for Step 1 LTA
const doesNotRequirePayment = 
  VV.Form.GetFieldValue('Payment Not Required') === 'True' || VV.Form.GetFieldValue("No Fees Required") === "True";
const formStatus = VV.Form.GetFieldValue('Status');
const roles = VV.Form.Global.GetCurrentRoles();

const isProponent = roles.includes('proponent');
const isOfficeStaff = roles.includes('office staff');
const isVaultAccess = roles.includes('vaultaccess');

let setSubmitButtonVisible = false;
let setResubmitButtonVisible = false;

if (isProponent) {
  if (['Needs Submission'].includes(formStatus)) {
    setSubmitButtonVisible = true;
  }
  if (['Required Signatures Received'].includes(formStatus) && doesNotRequirePayment) {
    setSubmitButtonVisible = true;
  }
  if (['Pending Revisions'].includes(formStatus) && doesNotRequirePayment) {
    setResubmitButtonVisible = true;
  }
  if (['Needs Resubmission'].includes(formStatus)) {
    setResubmitButtonVisible = true;
  }

  // Hide buttons if autosubmission is needed
  if(VV.Form.GetFieldValue('AutoSubmissionNeeded') === 'True'){
    setSubmitButtonVisible = false;
  }
  if(VV.Form.GetFieldValue('AutoResubmitNeeded') === 'True'){
    setResubmitButtonVisible = false;
  }
}

if (isOfficeStaff || isVaultAccess) {
  if (formStatus === 'Draft') {
    setSubmitButtonVisible = true;
  }
  if (formStatus === 'Pending Revisions') {
    setResubmitButtonVisible = true;
  }
}

return Promise.all([
  VV.Form.SetFieldValue('Show Submit Button', setSubmitButtonVisible ? 'True' : 'False'),
  VV.Form.SetFieldValue('Show Resubmit Button', setResubmitButtonVisible ? 'True' : 'False'),
]);

