/*
    Function Name: Form_onLoad - Step 1 Long Term FPA
    Customer:      Washington DNR
    Purpose:       This function initializes the Step 1 Long Term FPA form.
                   It registers all DataGrids, ensures that the form instance is persisted
                   on first load, updates the browser URL to reference the saved record,
                   and sets up user roles, navigation, GIS data, and document paths.

    Parameters:    None

    Date of Dev:   --/--/----
    Last Rev Date: 10/29/2025

    --/--/---- - Previous contributors: Initial revision
    10/29/2025 - Matias Andrade: Added early form persistence and browser URL update logic to ensure the saved record reloads correctly after refresh.
    03/09/2026 - Zharich Barona: Added URL update after initial save to ensure the URL reflects the saved record ID, improving refresh behavior and navigation.
*/
const initialPromises = [];
// Get the current status of the form
try {
  const formStatus = VV.Form.GetFieldValue('Status');
  if (VV.Form.Global.isNullEmptyUndefined(formStatus)) {
    initialPromises.push(VV.Form.SetFieldValue('Status', 'Draft'));
  }

  // On every load, set No fees Required to False so the user must Validate and Proceed again
  if (formStatus.toLowerCase() === 'pending revisions') {
    initialPromises.push(VV.Form.SetFieldValue('No Fees Required', 'False'));
  }
} catch (error) {
  console.error('Error setting initial Status fields:', error);
}

// Register DataGrids
try {
  VV.Form.Global.RegisterDatagrids([
    'DG Landowner Businesses',
    'DG Landowners Signers',
    'DG Landowners',
    'DG Appendix D',
    'DG Appendix J',
    'DG Legal Description',
    'RRC Identifier Activity Map',
    'DG Wetlands Inventory',
    'DG Sensitive Site',
    'DG Roads Assessment',
  ]);
} catch (error) {
  console.error('Error registering datagrids:', error);
}

// Helper function for case-insensitive property access
function getPropertyCaseInsensitive(obj, propertyName) {
  if (!obj) return undefined;

  const keys = Object.keys(obj);
  const foundKey = keys.find((key) => key.toLowerCase() === propertyName.toLowerCase());

  return foundKey ? obj[foundKey] : undefined;
}

//Setting related FPAN ID for activity map on hidden field
initialPromises.push(
  VV.Form.CustomQuery('LTA 1DAY with FPAN Id', VV.Form.GetFieldValue('Top Form ID'))
    .then((res) => getPropertyCaseInsensitive(res?.[0], 'fpan id'))
    .then((fpanID) => {
      if (typeof fpanID === 'string' && fpanID.trim() !== '') {
        // fpanID is a non-empty, non-whitespace string
        return VV.Form.SetFieldValue('FPAN ID', fpanID);
      }
      return Promise.resolve();
    })
    .catch((err) => console.error(err))
);

//Loading activity map needed for btnActivityMap_onClick.js
//Check if there is a saved activity map view that we can use from the sub form
VV.Form.Template.LoadActivityMap();
// Initialize variables
const isSaved = VV.Form.GetFieldValue('Form Saved') === 'True';

VV.Form.ShowLoadingPanel();

// Add an early save + URL update to persist the record ID and update the browser URL.
Promise.all(initialPromises)
  .then(() => {
    try {
      VV.Form.Global.UpdateWindowLocationURL();
    } catch (urlErr) {
      console.error('Error updating URL after first save:', urlErr);
    }

    // Main execution chain - handle roles and sequential operations
    try {
      // Get roles directly (synchronous)
      const currentRoles = VV.Form.Global.GetCurrentRoles();

      // Process roles
      const isOfficeStaff = currentRoles.some((role) => role === 'office staff');
      const isProponent = currentRoles.some((role) => role === 'proponent');
      const isFieldStaff = currentRoles.some((role) => role === 'field staff');
      const isSignatory = currentRoles.some((role) => role === 'signatory');

      if (isSignatory) {
        VV.Form.Global.SignatoryDisableButtonByFieldName();
      }

      // Start sequential execution chain
      return Promise.all([
        VV.Form.SetFieldValue('isProponent', isProponent),
        VV.Form.SetFieldValue('isOfficeStaff', isOfficeStaff),
        VV.Form.SetFieldValue('isFieldStaff', isFieldStaff),
        VV.Form.SetFieldValue('UserRoles', currentRoles),
      ])
        .then(() => {
          if (isOfficeStaff) {
            return VV.Form.SetFieldValue('Created By Office Staff', true, true);
          }
          return Promise.resolve();
        })
        .then(() => {
          // Check if SetIndividual is needed based on specific conditions
          const IndividualIdPresent = VV.Form.GetFieldValue('Individual ID') !== '';
          const UserIdPresent = VV.Form.GetFieldValue('UserID') !== '';

          const needsSetIndividual = isProponent && (!IndividualIdPresent || !UserIdPresent);

          return needsSetIndividual;
        })
        .then((needsSetIndividual) => {
          // Execute SetIndividual if needed and wait for completion
          if (needsSetIndividual) {
            return VV.Form.Template.SetIndividual();
          }
          return Promise.resolve();
        })
        .then(() => VV.Form.Template.UpdateDocumentPath()) // Update document path after SetIndividual completes
        .then(() => VV.Form.Template.DeterminePayNowButtonVisibility()) // Pay Now button visibility
        .then(() => {
          // Loading activity map needed for btnActivityMap_onClick.js
          VV.Form.Global.GIS_onLoad(event);
          return Promise.resolve();
        })
        .then(() =>
          VV.Form.CustomQuery('LTA 1DAY with FPAN Id', VV.Form.GetFieldValue('Top Form ID'))
        ) // Get FPAN ID from custom query
        .then((res) => {
          // Process query result and set FPAN ID
          const fpanID = getPropertyCaseInsensitive(res?.[0], 'fpan id');

          if (typeof fpanID === 'string' && fpanID.trim() !== '') {
            return VV.Form.SetFieldValue('FPAN ID', fpanID);
          }

          return Promise.resolve();
        })
        .then(() => {
          // Load activity map as final step before save
          VV.Form.Template.LoadActivityMap();
          return Promise.resolve();
        })
        .then(() => VV.Form.Template.SetButtonVisibility()) // Submit and Resubmit button visibility
        .then(() => VV.Form.DoAjaxFormSave())
        .then(() => {
          try {
            VV.Form.Global.UpdateWindowLocationURL();
          } catch (urlErr) {
            console.error('Error updating URL after first save:', urlErr);
          }          
          VV.Form.HideLoadingPanel();
          return Promise.resolve();
        })
        .catch((error) => {
          console.error('Error in sequential execution:', error);

          // Even if something fails, still try to set essential UI elements
          try {
            VV.Form.Template.UpdateDocumentPath();
          } catch (docError) {
            console.error('Error setting document upload path in catch:', docError);
          }

          try {
            VV.Form.Template.DeterminePayNowButtonVisibility();
          } catch (payError) {
            console.error('Error determining pay now button visibility in catch:', payError);
          }

          try {
            VV.Form.Template.SetButtonVisibility();
          } catch (buttonError) {
            console.error('Error setting button visibility in catch:', buttonError);
          }

          try {
            VV.Form.Global.GIS_onLoad(event);
          } catch (gisError) {
            console.error('Error loading GIS in catch:', gisError);
          }

          try {
            VV.Form.Template.LoadActivityMap();
          } catch (mapError) {
            console.error('Error loading activity map in catch:', mapError);
          }
          VV.Form.HideLoadingPanel();
        });
    } catch (error) {
      console.error('Error getting current roles:', error);

      // Fallback execution if roles failed entirely
      try {
        VV.Form.Template.UpdateDocumentPath();
        VV.Form.Template.DeterminePayNowButtonVisibility();
        VV.Form.Template.SetButtonVisibility();
        VV.Form.Global.GIS_onLoad(event);
        VV.Form.Template.LoadActivityMap();
      } catch (fallbackError) {
        console.error('Error in fallback execution:', fallbackError);
      }
      VV.Form.HideLoadingPanel();
    }
  })
  .catch((error) => {
    console.error('Error during initial save / URL update:', error);

    VV.Form.HideLoadingPanel();
  });

