// btn_RemoveSelectedAppendixD_onClick.js for Step 1 LTA

const MAX_QUANTITY = 10;

const selectedItems = VV.Form.Global.DatagridFindSelectedRows("DG Appendix D");
const doOkFunction = () =>
  VV.Form.Template.DisableRelations(selectedItems, 'Appendix D Slope Stability Informational')

if (selectedItems.length > 0 && selectedItems.length <= MAX_QUANTITY) {
  const htmlContent = `<p>Do you want to remove the selected Appendix D?</p>`;

  VV.Form.Global.DisplayModal({
    HtmlContent: htmlContent,
    Icon: "question",
    okFunction: doOkFunction,
    Title: "Confirmation",
  });
} else {
  const htmlContent = `<p>Please select between one and ten Appendix D record(s) to remove.</p>`;

  VV.Form.Global.DisplayModal({
    HtmlContent: htmlContent,
    Icon: "error",
    Title: "Error",
  });
}

//Address_Line_1_onBlur for Step 1 Long Term FPA

const results = VV.Form.Template.FormValidation('Address Line 1');

if (results) {
  VV.Form.Template.FormValidation('Address Line 1');
} else {
  VV.Form.Global.AddressVerificationOnBlur('landOwnerInformationAddress');
}

//Form_onDataLoad for Step 1 Long Term FPA

//Modify default form save with stale check functionality
VV.Form.DoAjaxFormSave = VV.Form.Global.BuildAjaxFormSaveWithStaleCheck('zClientSideStep1LTFPALatestGUID');

//Loads required css/scripts for DisplayModal
VV.Form.Global.DisplayModalLoad();

//Loading activity map needed for btnActivityMap_onClick.js
VV.Form.Global.GIS_onLoad(event);

const results = VV.Form.Template.FormValidation("Zip Code");

if (results) {
  VV.Form.Template.FormValidation("Zip Code");
} else {
  VV.Form.Global.AddressVerificationOnBlur("landOwnerInformationAddress");
}

const MAX_QUANTITY = 10;

const selectedItems = VV.Form.Global.DatagridFindSelectedRows(
  'DG Wetlands Inventory'
);

const doOkFunction = () =>
  VV.Form.Template.DisableRelations(selectedItems, 'Wetlands');

if (selectedItems.length > 0 && selectedItems.length <= MAX_QUANTITY) {
  const htmlContent = `<p>Do you want to remove the selected Wetlands?</p>`;
  VV.Form.Global.DisplayModal({
    Icon: 'question',
    Title: 'Confirmation',
    HtmlContent: htmlContent,
    okFunction: doOkFunction,
  });
} else {
  const htmlContent = `<p>Please select between one and ten Wetlands record(s) to remove.</p>`;
  VV.Form.Global.DisplayModal({
    HtmlContent: htmlContent,
    Icon: 'error',
    Title: 'Error',
  });
}
